import stringfrom agent import *from models.products import *import redef getexcerpt(txtlist):    excerpt = ''    txtlist = [o.strip() for o in txtlist]    for line in txtlist:        excerpt += ' ' + line        if re_search_once("([!?.])$", line) and len(line) > 100:            break    excerpt = re.compile("\s+").sub(' ', excerpt)    return excerpt.strip()def process_category(data, context, session):    for categoryline in data.xpath("//div[@id='content']//a[text()[string-length(normalize-space(.))>1]]"):        context['category_url'] = categoryline.xpath("@href").string()        context['category_name'] = categoryline.xpath("text()[string-length(normalize-space(.))>1]").string()        if context['category_name'] and context['category_url']:          session.queue(Request(context['category_url']), process_view_category, context)          #session.emit(Product(name = 'product_name', url = category_url, category = category_name))def process_view_category(data, context, session):  if data.xpath("//table[@frame='VOID']/tr[count(td)=2]"):    for view_categoryline in data.xpath("//table[@frame='VOID']/tr[count(td)=2]"):        context['product_url'] = view_categoryline.xpath("td[1]//a/@href").string()        context['product_name'] = view_categoryline.xpath("td[1]//a//text()[string-length(normalize-space(.))>0]").string()        context['rating'] = view_categoryline.xpath("td[2]/text()[regexp:test(.,'(\d+)')]").string()        if context['product_url'] and context['product_name'] and context['rating']:            session.queue(Request(context['product_url']), process_product, context)            #session.emit(Product(ssid = context['date'], name = context['product_name'], url = context['product_url'], category = context['category_name']))  else:    c1 = context['category_name']    for categoryline in data.xpath("//div[@id='content']//a[img/@alt]"):        context['category_url'] = categoryline.xpath("@href").string()        c2 = categoryline.xpath("img/@alt").string()        if context['category_name'] and c2:          context['category_name'] = c1 + '|' + c2           session.queue(Request(context['category_url']), process_view_category, context)          #session.emit(Product(name = 'product_name', url = category_url, category = category_name))def process_product(data, context, session):     product = Product()    product.url = context['product_url']     product.ssid = context['product_name']    product.name = context['product_name']    product.category = context['category_name']    for imageline in data.xpath("//div[@id='content']//img[contains(@src,'/Reviews/')]"):        url_image = imageline.xpath("@src").string()        if url_image:           product.properties.append(ProductProperty(type='image' , value = {'src': url_image, 'type': 'product'}))    review = Review()    review.type = 'pro'    review.ssid = product.ssid    review.url = product.url    review.title = product.name    username = data.xpath("//text()[regexp:test(.,'Publisher:')]").string()    if username:        user = username.replace('Publisher:','')        review.authors = Person(name = user, ssid = user)     txtlist = data.xpath("//div[@id='content']//p[.//text()[string-length(normalize-space(.))>100]]//text()[not(ancestor::script)]").strings()    if txtlist:        excerpt = getexcerpt(txtlist)        if excerpt:            review.properties.append(ReviewProperty(type='excerpt', value = excerpt))    review.grades.append(Grade(name= 'SCORE', value = context['rating'], worst = 0,  best = 100, type = 'overall'))    for gradeline in data.xpath("//div[@id='content']//p/span[contains(@class,'style') and text()[string-length(normalize-space(.))>1]]"):        rating_name = gradeline.xpath("text()[string-length(normalize-space(.))>1]").string()        rating_value = gradeline.xpath("following-sibling::text()[string-length(normalize-space(.))>1]").string()        if not rating_value:          rating_value = gradeline.xpath("text()[string-length(normalize-space(.))>1]").string()        if rating_value and rating_name:            rating_name2 = re_search_once('(.+):', rating_name)            rating_value2 = re_search_once('(\d+)', rating_value)            if rating_name2 and rating_value2:               review.grades.append(Grade(name= rating_name2, value = rating_value2, worst = 0, best = 100))    product.reviews.append(review)    session.emit(product)def run(context, session):    sb = SessionBreak()    sb.max_requests = 25000    session.sessionbreakers = [ sb ]    session.queue(Request('http://www.familyfriendlygaming.com/Reviews%20listing.html'), process_category, {}) 